import React from 'react';

interface SkillGroupProps {
  title: string;
  icon: string;
  skills: string[];
}

const SkillGroup: React.FC<SkillGroupProps> = ({ title, icon, skills }) => (
  <div style={{ marginBottom: 24, padding: 14, border: '2px inset #c0c0c0', background: '#f8f8f8' }}>
    <h3 style={{ fontSize: 13, marginBottom: 10, display: 'flex', alignItems: 'center', gap: 6 }}>
      <span>{icon}</span>{title}
    </h3>
    <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6 }}>
      {skills.map((s, i) => (
        <span key={i} style={{
          padding: '3px 10px',
          background: '#c0c0c0',
          borderTop: '1px solid #ffffff',
          borderLeft: '1px solid #ffffff',
          borderRight: '1px solid #404040',
          borderBottom: '1px solid #404040',
          fontSize: 11,
        }}>{s}</span>
      ))}
    </div>
  </div>
);

const Skills: React.FC = () => (
  <div style={{ padding: 24, maxWidth: 700 }}>
    <h2 style={{ fontSize: 22, borderBottom: '2px solid #c0c0c0', paddingBottom: 8, marginBottom: 20 }}>Technical Skills & Certifications</h2>

    <SkillGroup icon="☁️" title="Cloud Platforms" skills={['AWS Cloud Practitioner', 'Azure AZ-900', 'Azure AZ-104', 'Microsoft Entra ID', 'Azure Active Directory']} />
    <SkillGroup icon="🔒" title="Security & Compliance" skills={['ISC2 Certified in Cybersecurity', 'Microsoft Defender', 'Microsoft Purview', 'Security Incident Response', 'ISC2 CC']} />
    <SkillGroup icon="💻" title="Endpoint & Device Management" skills={['Microsoft Intune', 'SCCM', 'Knox Management', 'Flexera Snow', 'Windows', 'iOS', 'Linux']} />
    <SkillGroup icon="📊" title="Microsoft 365 & Monitoring" skills={['Teams Admin', 'Exchange', 'Purview', 'AppDynamics', 'Zscaler ELK', 'Thousand Eyes']} />
    <SkillGroup icon="🏢" title="Business Applications" skills={['Microsoft FinOps', 'Dynamics 365 Retail', 'SAP C/4HANA', 'EFTPOS / POS Systems', 'Farmlands Pro']} />
    <SkillGroup icon="⚙️" title="Scripting & Automation" skills={['PowerShell', 'Active Directory', 'ITIL Service Management', 'License Management', 'Network Configuration']} />
  </div>
);

export default Skills;
